// Each line transforms the selection.
// The chain IS the program.

const data = [
  { date: '2024-01-15', value: 42 },
  { date: '2024-02-20', value: 67 },
  { date: '2024-03-10', value: 55 }
];

const x = d3.scaleTime()
  .domain(d3.extent(data, d => d.date))
  .range([0, width]);

svg.selectAll('circle')
  .data(data)
  .join('circle')
  .attr('cx', d => x(d.date))
  .attr('cy', d => y(d.value))
  .attr('r', 5);

const x = d3.scaleBand()
  .domain(data.map(d => d.category))
  .range([0, width])
  .padding(0.2);  // 20% gap between bars

// x('Apples')     → pixel position
// x.bandwidth()   → bar width (auto-calculated)

svg.selectAll('rect')
  .data(data)
  .join('rect')
  .attr('x', d => x(d.category))
  .attr('width', x.bandwidth())
  .attr('y', d => y(d.value))
  .attr('height', d => height - y(d.value));

const svg = d3.select('#chart')
  .append('svg')
  .attr('viewBox', '0 0 600 400');

